void checkEngine(double temperature) {
  if (temperature > 250) {
    // DANGER! Trigger the alarm!
    throw Exception('Engine is overheating!');
  }
  print('Engine temperatures normal.');
}

void main() {
  try {
    checkEngine(300.0); // This will blow up!
  } catch (e) {
    print('MECHANIC ALERT: $e');
  }
}
